package com.ses.service.impl;
import com.ses.entity.ContractDocument; import com.ses.service.CloudSignClient; import org.springframework.beans.factory.annotation.Value; import org.springframework.http.*; import org.springframework.stereotype.Component; import org.springframework.web.client.RestTemplate; import java.util.*;
@Component public class CloudSignClientImpl implements CloudSignClient {
 @Value("${cloudsign.enabled:false}") boolean enabled; @Value("${cloudsign.base-url:}") String baseUrl; @Value("${cloudsign.token:}") String token; private final RestTemplate rest=new RestTemplate();
 public Result send(ContractDocument d){ if(!enabled||baseUrl==null||baseUrl.isBlank()) return new Result("stub-"+d.getId(),null,"送信中",null,null); HttpHeaders h=new HttpHeaders(); h.setBearerAuth(token); h.setContentType(MediaType.APPLICATION_JSON); Map<String,Object> body=Map.of("title","SES契約 "+d.getContractId(),"name",d.getRecipientName(),"email",d.getRecipientEmail()); ResponseEntity<Map> r=rest.postForEntity(baseUrl+"/documents",new HttpEntity<>(body,h),Map.class); Map m=r.getBody()==null?Map.of():r.getBody(); return new Result(Objects.toString(m.get("id"),""),Objects.toString(m.get("file_id"),null),"送信中",null,null); }
 public Result status(String id){ if(!enabled||id==null||id.startsWith("stub-")) return new Result(id,null,"確認中",null,null); ResponseEntity<Map> r=rest.getForEntity(baseUrl+"/documents/"+id,Map.class); Map m=r.getBody()==null?Map.of():r.getBody(); return new Result(id,Objects.toString(m.get("file_id"),null),Objects.toString(m.getOrDefault("status","確認中"),"確認中"),null,null); }
}
